# Example: Minimal internal MCP server using the Python MCP SDK
from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp import types
import json

app = Server("internal-crm-tools")

@app.list_tools()
async def list_tools() -> list[types.Tool]:
    return [
        types.Tool(
            name="get_customer",
            description="Retrieve a customer record by ID or email from the internal CRM.",
            inputSchema={
                "type": "object",
                "properties": {
                    "identifier": {
                        "type": "string",
                        "description": "Customer ID (C-XXXXX) or email address"
                    }
                },
                "required": ["identifier"]
            }
        ),
        types.Tool(
            name="list_open_tickets",
            description="List open support tickets for a customer.",
            inputSchema={
                "type": "object",
                "properties": {
                    "customer_id": {"type": "string"},
                    "limit": {"type": "integer", "maximum": 50}
                },
                "required": ["customer_id"]
            }
        )
    ]

@app.call_tool()
async def call_tool(name: str, arguments: dict) -> list[types.TextContent]:
    if name == "get_customer":
        result = await crm_client.get_customer(arguments["identifier"])
        return [types.TextContent(type="text", text=json.dumps(result))]
    elif name == "list_open_tickets":
        tickets = await crm_client.list_tickets(
            customer_id=arguments["customer_id"],
            status="open",
            limit=arguments.get("limit", 10)
        )
        return [types.TextContent(type="text", text=json.dumps(tickets))]
    else:
        raise ValueError(f"Unknown tool: {name}")

async def main():
    async with stdio_server() as (read_stream, write_stream):
        await app.run(read_stream, write_stream, app.create_initialization_options())
